const request = $input.first().json;
const body = request.body ?? {};
const config = Object.freeze({
  allowedOrigin: 'https://paesegregori.casaortegaimoveis.com.br',
  spreadsheetId: '13y_9C-c3rQ6MYaIxPFOzpivG338EvpjDbF7WbcKY3aM',
  sheetName: 'Página1',
  whatsappRecipient: '5511919890615',
  evolutionBaseUrl: 'https://evo.figueiramarketing.com.br',
  evolutionInstance: 'Guilherme014',
  projectName: 'Nhambí Moema | Carolline'
});

const clean = (value, max = 500) => String(value ?? '').replace(/\s+/g, ' ').trim().slice(0, max);
const origin = clean(request.headers?.origin, 300);
if (origin !== config.allowedOrigin) throw new Error('Origem não autorizada.');
if (clean(body.website, 200)) throw new Error('Envio bloqueado.');

const phone = clean(body.phone, 30);
const phoneDigits = phone.replace(/\D/g, '');
const lead = {
  id: clean(body.id, 80),
  created_time: new Date().toISOString(),
  ad_id: clean(body.ad_id, 80),
  ad_name: clean(body.ad_name, 200),
  adset_id: clean(body.adset_id, 80),
  adset_name: clean(body.adset_name, 200),
  campaign_id: clean(body.campaign_id, 80),
  campaign_name: clean(body.campaign_name, 200),
  form_id: clean(body.form_id, 80) || 'leadForm',
  form_name: clean(body.form_name, 200) || 'Landing Page | Nhambí Moema | Carolline',
  is_organic: Boolean(body.is_organic),
  platform: clean(body.platform, 50) || 'website',
  nome_completo: clean(body.name, 120),
  telefone: phoneDigits,
  email: clean(body.email, 180),
  inbox_url: clean(body.inbox_url, 2000),
  lead_status: 'CREATED',
  interest: clean(body.interest, 80),
  best_contact_time: clean(body.schedule, 120),
  message: clean(body.message, 1000),
  utm_source: clean(body.utm_source, 200),
  utm_medium: clean(body.utm_medium, 200),
  utm_campaign: clean(body.utm_campaign, 300),
  utm_content: clean(body.utm_content, 300),
  utm_term: clean(body.utm_term, 300),
  fbclid: clean(body.fbclid, 1000),
  landing_url: clean(body.landing_url, 2000),
  referrer: clean(body.referrer, 2000),
  telefone_valido: phoneDigits.length >= 10 && phoneDigits.length <= 13,
  config
};

if (!lead.id || !lead.nome_completo || !lead.telefone || !lead.interest) {
  throw new Error('Campos obrigatórios ausentes.');
}

return [{ json: lead }];
